use std::collections::HashMap;

struct Widget { id: u32, name: String } 

impl FromIterator<Widget> for HashMap<u32, String> {
    fn from_iter<I>(iter: I) -> Self 
    where
        I: IntoIterator<Item = Widget>,
    {
        let mut map = HashMap::new();
        for widget in iter.into_iter() {
            map.insert(widget.id, widget.name);
        }
        map
    }
}

fn main() {
    let widgets = vec![ 
        Widget { id: 1, name: String::from("Apple") },
        Widget { id: 2, name: String::from("Banana") } 
    ];

    let fruit_map: HashMap<u32, String> = widgets.into_iter().collect();

    println!("Processed map entries:");
    for (id, name) in &fruit_map {
        println!("ID: {}, Name: {}", id, name);
    }
}

