use std::collections::HashMap;

struct Item {
    name: String,
    value: i32,
}

impl From<Item> for HashMap<String, i32> {
    fn from(item: Item) -> Self {
        let mut map = HashMap::new();
        map.insert(item.name, item.value);
        map
    }
}

fn process_items(inputs: Vec<Item>) -> Vec<HashMap<String, i32>> {
    inputs.into_iter().map(|item| HashMap::from(item)).collect()
}

fn main() {
    let items = vec![ 
        Item { name: String::from("apple"), value: 10 },
        Item { name: String::from("banana"), value: 5 },
        Item { name: String::from("cherry"), value: 20 } 
    ];

    let results = process_items(items);

    for result_map in results {
        println!("Processed Map: {:?}", result_map);
    }
}

use std::collections::HashMap;

struct Item { 
    value: i32,
}

impl FromIterator<Item> for HashMap<String, i32> {
    fn from_iter<I>(iter: I) -> Self
    where
        I: IntoIterator<Item = Item>,
    {
        let mut map = HashMap::new();
        for item in iter.into_iter() {
            map.insert(format!("key_{}", item.value), item.value);
        }
        map
    }
}

fn main() {
    let data_source = vec![ 
        Item { value: 10 }, 
        Item { value: 5 }, 
        Item { value: 20 } 
    ];

    let result_map: HashMap<String, i32> = data_source.into_iter().collect();

    println!("Calculated map contents:");
    for (key, val) in &result_map {
        println!("{}: {}", key, val);
    }
}

use std::collections::HashMap;

struct Item { 
    id: u32,
    name: String,
}

impl From<Item> for HashMap<u32, String> {
    fn from(item: Item) -> Self {
        let mut map = HashMap::new();
        map.insert(item.id, item.name);
        map
    }
}

fn main() {
    let items_to_process = vec![ 
        Item { id: 101, name: String::from("Apple") },
        Item { id: 202, name: String::from("Banana") } 
    ];

    let combined_map: HashMap<u32, String> = items_to_process.into_iter().fold(HashMap::new(), |mut acc, item| {
        let mut map = HashMap::new();
        map.insert(item.id, item.name);
        acc.extend(map);
        acc
    });

    println!("Processed Map: {:?}", combined_map);
}
